import{_ as a,o as r,c as e,ag as d}from"./chunks/framework.DXGyWiRo.js";const b=JSON.parse('{"title":"GEICO · 政府雇员保险公司","description":"","frontmatter":{},"headers":[],"relativePath":"03_companies/伯克希尔子公司/GEICO.md","filePath":"03_companies/伯克希尔子公司/GEICO.md"}'),l={name:"03_companies/伯克希尔子公司/GEICO.md"};function o(i,t,h,n,s,u){return r(),e("div",null,[...t[0]||(t[0]=[d('<h1 id="geico-·-政府雇员保险公司" tabindex="-1">GEICO · 政府雇员保险公司 <a class="header-anchor" href="#geico-·-政府雇员保险公司" aria-label="Permalink to &quot;GEICO · 政府雇员保险公司&quot;">​</a></h1><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>内容</th></tr></thead><tbody><tr><td><strong>全称</strong></td><td>Government Employees Insurance Company</td></tr><tr><td><strong>行业</strong></td><td>保险（汽车险为主）</td></tr><tr><td><strong>投资类型</strong></td><td>公开市场买入</td></tr><tr><td><strong>首次买入</strong></td><td>1951年（个人投资）</td></tr><tr><td><strong>伯克希尔建仓</strong></td><td>1976年</td></tr><tr><td><strong>持仓状态</strong></td><td>1996年全资收购，至今100%控股</td></tr><tr><td><strong>投资性质</strong></td><td>巴菲特最成功的投资之一</td></tr></tbody></table><h2 id="投资时间线" tabindex="-1">投资时间线 <a class="header-anchor" href="#投资时间线" aria-label="Permalink to &quot;投资时间线&quot;">​</a></h2><table tabindex="0"><thead><tr><th>年份</th><th>事件</th><th>出处</th></tr></thead><tbody><tr><td>1951</td><td>巴菲特首次发现GEICO，个人投资</td><td>《滚雪球》</td></tr><tr><td>1976</td><td>伯克希尔开始买入GEICO股票</td><td>1976年股东信</td></tr><tr><td>1977</td><td>持股约430万股（优先股+普通股）</td><td>1977年股东信</td></tr><tr><td>1980</td><td>持股比例达33%</td><td>1980年股东信</td></tr><tr><td>1995</td><td>决定全资收购</td><td>1995年股东信</td></tr><tr><td>1996</td><td>完成全资收购，代价23亿美元</td><td>1996年股东信</td></tr></tbody></table><h2 id="历年股东信论述" tabindex="-1">历年股东信论述 <a class="header-anchor" href="#历年股东信论述" aria-label="Permalink to &quot;历年股东信论述&quot;">​</a></h2><h3 id="_1977年" tabindex="-1">1977年 <a class="header-anchor" href="#_1977年" aria-label="Permalink to &quot;1977年&quot;">​</a></h3><blockquote><p>GEICO是我们最重要的持仓之一。1977年底我们持有约200万股可转换优先股和130万股普通股。</p></blockquote><p>GEICO的主要吸引力在于其<strong>低成本运营模式</strong>——直接向政府雇员销售汽车保险，省去中间代理商佣金，成本优势明显。</p><h3 id="_1976年-首次买入" tabindex="-1">1976年（首次买入） <a class="header-anchor" href="#_1976年-首次买入" aria-label="Permalink to &quot;1976年（首次买入）&quot;">​</a></h3><p>GEICO当时陷入严重困境——承保亏损、资本金不足、监管介入。巴菲特判断：</p><ol><li>核心商业模式没有问题（低成本优势依然存在）</li><li>新任CEO约翰·伯恩（John Byrne）有能力扭亏</li><li>危机导致股价极具吸引力</li></ol><h3 id="_1980年" tabindex="-1">1980年 <a class="header-anchor" href="#_1980年" aria-label="Permalink to &quot;1980年&quot;">​</a></h3><blockquote><p>GEICO的成本优势是其护城河。</p></blockquote><p>巴菲特明确提出GEICO的<strong>护城河</strong>概念——低成本结构难以复制，竞争对手即便知道也很难做到。</p><h3 id="_1995年-决定全资收购" tabindex="-1">1995年（决定全资收购） <a class="header-anchor" href="#_1995年-决定全资收购" aria-label="Permalink to &quot;1995年（决定全资收购）&quot;">​</a></h3><blockquote><p>我们喜欢GEICO，喜欢它的商业模式，喜欢它的管理层，喜欢它的价格。</p></blockquote><p>决定以23亿美元收购剩余67%股权，这是伯克希尔当时最大一笔收购。</p><h3 id="_1996年至今" tabindex="-1">1996年至今 <a class="header-anchor" href="#_1996年至今" aria-label="Permalink to &quot;1996年至今&quot;">​</a></h3><p>GEICO成为伯克希尔保险业务的核心支柱之一，贡献大量<strong>保险浮存金</strong>用于投资。巴菲特每年股东信都会单独讨论GEICO的承保表现。</p><h2 id="投资逻辑拆解" tabindex="-1">投资逻辑拆解 <a class="header-anchor" href="#投资逻辑拆解" aria-label="Permalink to &quot;投资逻辑拆解&quot;">​</a></h2><h3 id="_1-商业模式护城河" tabindex="-1">1. 商业模式护城河 <a class="header-anchor" href="#_1-商业模式护城河" aria-label="Permalink to &quot;1. 商业模式护城河&quot;">​</a></h3><ul><li><strong>直销模式</strong>：省去代理商佣金，成本比同行低15-20%</li><li><strong>目标客群</strong>：政府雇员驾驶习惯相对谨慎，赔付率低</li><li><strong>规模效应</strong>：客户越多，固定成本摊薄越明显</li></ul><h3 id="_2-危机买入机会" tabindex="-1">2. 危机买入机会 <a class="header-anchor" href="#_2-危机买入机会" aria-label="Permalink to &quot;2. 危机买入机会&quot;">​</a></h3><p>1975-1976年GEICO濒临破产：</p><ul><li>盲目扩张导致承保亏损</li><li>监管要求补充资本金</li><li>股价从60美元跌至2美元</li></ul><p>巴菲特判断：<strong>危机是暂时的，护城河是永久的</strong>。</p><h3 id="_3-管理层能力" tabindex="-1">3. 管理层能力 <a class="header-anchor" href="#_3-管理层能力" aria-label="Permalink to &quot;3. 管理层能力&quot;">​</a></h3><p>约翰·伯恩（John Byrne）临危受命：</p><ul><li>削减成本</li><li>提高保费</li><li>收缩业务</li><li>重建资本金</li></ul><h3 id="_4-复利效应" tabindex="-1">4. 复利效应 <a class="header-anchor" href="#_4-复利效应" aria-label="Permalink to &quot;4. 复利效应&quot;">​</a></h3><p>1951年首次接触 → 1976年大举买入 → 1996年全资收购 → 持有至今</p><p>巴菲特与GEICO的关系持续了<strong>70多年</strong>，这是&quot;长期持有&quot;的极致案例。</p><h2 id="关键数据" tabindex="-1">关键数据 <a class="header-anchor" href="#关键数据" aria-label="Permalink to &quot;关键数据&quot;">​</a></h2><table tabindex="0"><thead><tr><th>指标</th><th>数值</th></tr></thead><tbody><tr><td>1951年买入价</td><td>约$20/股</td></tr><tr><td>1976年危机价</td><td>约$2/股</td></tr><tr><td>1996年收购价</td><td>约$70/股</td></tr><tr><td>持有至今增值</td><td>数百倍</td></tr><tr><td>2023年保费收入</td><td>约$390亿美元</td></tr><tr><td>市场份额</td><td>美国第二大汽车保险公司</td></tr></tbody></table><h2 id="相关人物" tabindex="-1">相关人物 <a class="header-anchor" href="#相关人物" aria-label="Permalink to &quot;相关人物&quot;">​</a></h2><ul><li>[[沃伦·巴菲特]] - 投资决策者</li><li>[[约翰·伯恩]] - 1976年临危受命的CEO</li><li>[[洛里默·戴维森]] - GEICO创始人，1951年向巴菲特解释商业模式</li><li>[[路易斯·辛普森]] - 1996年后负责GEICO投资组合</li></ul><h2 id="相关主题" tabindex="-1">相关主题 <a class="header-anchor" href="#相关主题" aria-label="Permalink to &quot;相关主题&quot;">​</a></h2><ul><li>[[保险业务]] - 伯克希尔核心板块</li><li>[[护城河]] - GEICO的成本优势</li><li>[[危机投资]] - 1976年困境反转</li><li>[[长期持有]] - 70年的复利故事</li></ul><h2 id="扩展阅读" tabindex="-1">扩展阅读 <a class="header-anchor" href="#扩展阅读" aria-label="Permalink to &quot;扩展阅读&quot;">​</a></h2><ul><li>《滚雪球》第一部分：巴菲特1951年拜访GEICO的故事</li><li>1995年股东信：全资收购决策过程</li><li>1976年股东信：危机买入的时机判断</li></ul><hr><blockquote><p>链接：[[保险业务]] | [[护城河]] | [[1976年巴菲特致股东的信]] | [[1995年巴菲特致股东的信]]</p></blockquote>',43)])])}const q=a(l,[["render",o]]);export{b as __pageData,q as default};
